const long long mod = 1e9 + 7;
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N;
        scanf("%lld", &N);
        long long ans = 0;
        long long dp[100][100];
        for (int i = 1; i <= N; i++) {
            long long x = i / 2;
            long long y = i % 2;
            if (x == 0) {
                dp[x][y] = 1;
            } else {
                dp[x][y] = (dp[x - 1][y] + 1) % mod;
                if (y == 0) {
                    dp[x][y] = (dp[x][y] + dp[x - 1][1]) % mod;
                } else {
                    dp[x][y] = (dp[x][y] + dp[x - 1][0]) % mod;
                }
            }
            ans = (ans + dp[x][y]) % mod;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

